export const bankDepositMethodCopyVersion = 'v1';

export const bankDepositMethodHelper =
  "Selecting bank deposit will print your bank's name, branch address, and full " +
  'account number on the face of the notice. California Code of Civil Procedure ' +
  '\u00A7 1161(2) requires these details to appear on the notice for this payment ' +
  'option to be valid. If account-number visibility on a posted notice is a ' +
  'concern, consider opening a dedicated rent-collection account so your ' +
  'operating-account number is never disclosed.';

export const bankDepositMethodDisclosureExpandLabel = 'Why is this required?';

export const bankDepositMethodDisclosure =
  'Why your account number appears on the notice. When you offer bank deposit as ' +
  'a payment option, California Code of Civil Procedure \u00A7 1161(2) requires the ' +
  'notice to identify the financial institution, the branch address (within five ' +
  'miles of the rental property), and the account number where rent may be ' +
  'deposited. The statute names the account number specifically \u2014 a masked or ' +
  'truncated number does not satisfy the requirement and can expose the notice to ' +
  'challenge in an unlawful detainer proceeding.\n\n' +
  'If privacy is a concern, you have two compliant options:\n\n' +
  '1. Skip bank deposit on this notice. It is one of four optional payment ' +
  'methods. In Person and By Mail satisfy the statute on their own.\n\n' +
  '2. Use a dedicated rent-collection account. Open a separate account used only ' +
  'for inbound rent. The disclosed account number is then the rent-collection ' +
  'account, not your operating account.\n\n' +
  'This is broker guidance to help you weigh the trade-off \u2014 not legal advice. ' +
  'For questions specific to your situation, consult a California licensed ' +
  'attorney of your choosing.';
